    processlist: `select substring_index(node.TreeItem_Title,'Process -',-(1)) AS Process,node.TreeItem_Type_ID AS TreeItem_Type_ID,node.TreeItem_ID AS TreeItem_ID,node.TreeItem_Manager_ID AS TreeItem_Manager_ID,node.Process_Secondary_Owner AS Process_Secondary_Owner,node.per_scheme_manager AS per_scheme_manager,node.Parent_ID AS Parent_ID,node.Status_ID AS Status_ID,node.Logged_ID AS Logged_ID,node2.TreeItem_Title AS Parent,concat(owner.User_FirstName,' ',owner.User_LastName) AS Owner,(select concat(tbl_common_users.User_FirstName,' ',tbl_common_users.User_LastName) from tbl_common_users where @@extra@@ and (tbl_common_users.User_ID = node.Process_Secondary_Owner)) AS second_Owner from ((tbl_common_organization_tree node join tbl_common_organization_tree node2 on((node.Parent_ID = node2.TreeItem_ID))) left join tbl_common_users owner on((node.TreeItem_Manager_ID = owner.User_ID))) where @@extra@@ and (node.Status_ID = 1) ;`,
    raw_data: `select r.KPI_rawData_ID AS KPI_rawData_ID,r.KPI_rawData_Name AS KPI_rawData_Name,f.KPI_Format_Type AS KPI_Format_Type,freq.KPI_Freq_Type AS KPI_Freq_Type from ((tbl_kpi_rawdata r left join tbl_kpi_format f on((r.KPI_rawData_IDFormat = f.KPI_Format_ID))) left join tbl_kpi_freq freq on((r.KPI_RawData_FrequencyID = freq.KPI_Freq_ID))) where @@extra@@ and (r.Status_ID = '1') ;`,
