    reminder_detail: `select details.entry_id AS entry_id,reminder.reminder_name AS reminder_name,module.Module_Name AS Module_Name,details.reminder_days AS reminder_days,details.reminder_message AS reminder_message from ((tbl_common_reminder_details details join tbl_common_reminder reminder on((details.reminder_id = reminder.reminder_id))) join tbl_common_modules module on((reminder.reminder_module = module.Module_ID))) where @@extra@@ and (details.Status_ID = '1') ;`,
