    return_complaints_customers: `select cust.Customer_ID AS Customer_ID,concat(cust.Customer_FirstName,' ',cust.Customer_LastName,' ( ',cust.Customer_Company,' )') AS Company,ncr.NCR_Process AS NCR_Process,count(ncr.NCR_Customer_ID) AS Total from (tbl_ncr ncr left join tbl_all_customers cust on((ncr.NCR_Customer_ID = cust.Customer_ID))) where @@extra@@ and ((ncr.Status_ID <> 0) and (ncr.NCR_Category = 4)) group by ncr.NCR_Customer_ID ;`,
