    user_levels: `select all_users.User_ID AS User_ID,concat(all_users.User_FirstName,' ',all_users.User_LastName) AS userFullName,group_concat(levels.level_id separator ',') AS userLevels from (tbl_common_users all_users left join tbl_common_users_levels levels on((levels.user_id = all_users.User_ID))) where @@extra@@ and ((all_users.Status_ID = 1) and (levels.Status_ID = 1) and (all_users.User_ID > 2)) group by levels.user_id ;`,
    user_role_scope: `select user_levels.user_level_id AS user_level_id,user_levels.user_id AS user_id,user_levels.level_id AS level_id,user_levels.role_id AS role_id,tree.TreeItem_Title AS TreeItem_Title,parents.TreeItem_Title AS parent_title,tree.TreeItem_Type_ID AS TreeItem_Type_ID,roles.Role_Name AS Role_Name,user_levels.Status_ID AS Status_ID,convert((case when (user_levels.Status_ID = 1) then 'Active' when (user_levels.Status_ID = 0) then 'Suspended' else '--' end) using utf8mb3) AS Status_name from (((tbl_common_users_levels user_levels join tbl_common_organization_tree tree on((user_levels.level_id = tree.TreeItem_ID))) left join tbl_common_organization_tree parents on((parents.TreeItem_ID = tree.Parent_ID))) join tbl_common_roles roles on((user_levels.role_id = roles.Role_ID))) where @@extra@@ and ((tree.Status_ID = 1) and (roles.Status_ID = 1) and (user_levels.Status_ID = 1)) ;`,
    users: `select users.User_ID AS User_ID,concat(users.User_FirstName,' ',users.User_LastName) AS User_Name,users.User_Email AS User_Email,users.Status_ID AS Status_ID,users.number_of_signin AS number_of_signin,concat(users.User_WorkPhone,'/Ext:',users.User_OfficeExtension) AS Phone_Ext,pass.user_password AS password,group_concat(roles.Role_ID separator ',') AS Role_ID,group_concat(roles.Role_Name separator '<br>') AS Role_Name,group_concat(concat(roles.Role_Name,' (',levels.TreeItem_Title,')') separator '<br>') AS Roles from ((((tbl_common_users users left join tbl_common_users_levels user_roles_levels on((users.User_ID = user_roles_levels.user_id))) left join tbl_common_roles roles on((user_roles_levels.role_id = roles.Role_ID))) left join tbl_common_organization_tree levels on((user_roles_levels.level_id = levels.TreeItem_ID))) left join tbl_user_password pass on((pass.User_ID = users.User_ID))) where @@extra@@ and ((users.Status_ID = 1) and (user_roles_levels.Status_ID = 1) and (levels.Status_ID = 1) and (roles.Status_ID = 1) and (users.User_ID >= 2)) group by users.User_ID ;`,
    users_articles: `select concat(users.User_FirstName,' ',users.User_LastName) AS User,articles.Article_Upload_Date AS Article_Upload_Date,articles.Article_Name AS Article_Name,articles.Article_ID AS Article_ID,articles.Group_ID AS Group_ID from (tbl_knowledge_article articles join tbl_common_users users on((articles.User_ID = users.User_ID))) where @@extra@@ and (articles.Status_ID = 1) ;`,
    users_group_knowledge: `select groupusers.Group_User_ID AS Group_User_ID,concat(users.User_FirstName,' ',users.User_LastName) AS UserDetails,(select count(tbl_knowledge_article.Article_ID) from tbl_knowledge_article where @@extra@@ and ((tbl_knowledge_article.User_ID = groupusers.User_ID) and (tbl_knowledge_article.Group_ID = groupusers.Group_ID))) AS art_user,(select count(tbl_knowledge_idea.Idea_ID) from tbl_knowledge_idea where @@extra@@ and ((tbl_knowledge_idea.User_ID = groupusers.User_ID) and (tbl_knowledge_idea.Group_ID = groupusers.Group_ID))) AS idea_user,groupusers.User_ID AS User_ID,groupusers.Group_ID AS Group_ID,((select count(disc.Article_Discussion_ID) from (tbl_knowledge_article_discussion disc left join tbl_knowledge_article art on((disc.Article_ID = art.Article_ID))) where @@extra@@ and ((disc.Article_Commentor_ID = groupusers.User_ID) and (art.Group_ID = groupusers.Group_ID))) + (select count(disc.Discussion_ID) from (tbl_knowledge_idea_discussion disc left join tbl_knowledge_idea idea on((disc.Idea_ID = idea.Idea_ID))) where @@extra@@ and ((disc.User_ID = groupusers.User_ID) and (idea.Group_ID = groupusers.Group_ID)))) AS Total_Discussion from (tbl_knowledge_group_users groupusers left join tbl_common_users users on((groupusers.User_ID = users.User_ID))) where @@extra@@ and ((users.Status_ID = 1) and (groupusers.Status_ID = 1)) ;`,
    users_ideas: `select concat(users.User_FirstName,' ',users.User_LastName) AS User,ideas.Idea_Upload_Date AS Idea_Upload_Date,ideas.Idea_Title AS Idea_Title,ideas.Idea_ID AS Idea_ID,ideas.Group_ID AS Group_ID from (tbl_knowledge_idea ideas join tbl_common_users users on((ideas.User_ID = users.User_ID))) where @@extra@@ and (ideas.Status_ID = 1) ;`,
